const crcTable = Array.from({ length: 256 }, (_, index) => {
	let value = index;
	for (let bit = 0; bit < 8; bit++) value = value & 1 ? 0xedb88320 ^ (value >>> 1) : value >>> 1;
	return value >>> 0;
});

function crc32(buffer) {
	let value = 0xffffffff;
	for (const byte of buffer) value = crcTable[(value ^ byte) & 0xff] ^ (value >>> 8);
	return (value ^ 0xffffffff) >>> 0;
}

function dosTime(date = new Date()) {
	return ((date.getHours() & 0x1f) << 11) | ((date.getMinutes() & 0x3f) << 5) | ((date.getSeconds() / 2) & 0x1f);
}

function dosDate(date = new Date()) {
	return (((date.getFullYear() - 1980) & 0x7f) << 9) | (((date.getMonth() + 1) & 0xf) << 5) | (date.getDate() & 0x1f);
}

function u16(value) {
	const buffer = Buffer.alloc(2);
	buffer.writeUInt16LE(value);
	return buffer;
}

function u32(value) {
	const buffer = Buffer.alloc(4);
	buffer.writeUInt32LE(value >>> 0);
	return buffer;
}

async function writeZip(zipPath, files, baseDir) {
	const localParts = [];
	const centralParts = [];
	let offset = 0;
	for (const rel of files) {
		const name = Buffer.from(rel, "utf8");
		const data = await readFile(path.join(baseDir, rel));
		const crc = crc32(data);
		const local = Buffer.concat([
			u32(0x04034b50), u16(20), u16(0), u16(0), u16(dosTime()), u16(dosDate()), u32(crc), u32(data.length), u32(data.length), u16(name.length), u16(0), name, data,
		]);
		localParts.push(local);
		centralParts.push(Buffer.concat([
			u32(0x02014b50), u16(20), u16(20), u16(0), u16(0), u16(dosTime()), u16(dosDate()), u32(crc), u32(data.length), u32(data.length),
			u16(name.length), u16(0), u16(0), u16(0), u16(0), u32(0), u32(offset), name,
		]));
		offset += local.length;
	}
	const central = Buffer.concat(centralParts);
	const eocd = Buffer.concat([u32(0x06054b50), u16(0), u16(0), u16(files.length), u16(files.length), u32(central.length), u32(offset), u16(0)]);
	await writeFile(zipPath, Buffer.concat([...localParts, central, eocd]));
}

function escapeHtml(value) {
	return String(value ?? "")
		.replaceAll("&", "&amp;")
		.replaceAll("<", "&lt;")
		.replaceAll(">", "&gt;")
		.replaceAll('"', "&quot;");
}

function titleize(name) {
	return name.split("-").map((part) => part ? part[0].toUpperCase() + part.slice(1) : part).join(" ");
}

function truncate(value, max) {
	const text = String(value ?? "");
	return text.length > max ? `${text.slice(0, max - 1)}…` : text;
}

function sqlString(value) {
	return String(value ?? "").replaceAll("'", "''");
}

function seedMigration(tasks) {
	const rows = tasks.map((task) => {
		const values = [
			task.name,
			task.title,
			task.description,
			task.author,
			task.stats.downloads,
			task.stats.likes,
			task.stats.favorites,
			"2026-06-30T00:00:00.000Z",
		];
		return `('${sqlString(values[0])}', '${sqlString(values[1])}', '${sqlString(values[2])}', '${sqlString(values[3])}', ${values[4]}, ${values[5]}, ${values[6]}, '${values[7]}')`;
	}).join(",\n\t");
	return `-- Generated by scripts/build-task-share.mjs.
-- Seeds the official catalog into D1; live user interactions update counters after deploy.

INSERT INTO tasks (name, title, description, author_name, download_count, like_count, favorite_count, created_at)
VALUES
\t${rows}
ON CONFLICT(name) DO UPDATE SET
\ttitle = excluded.title,
\tdescription = excluded.description,
\tauthor_name = excluded.author_name;
`;
}

async function listFiles(dir, prefix = "") {
	const entries = await readdir(dir, { withFileTypes: true });
	const files = [];
	for (const entry of entries) {
		const rel = prefix ? `${prefix}/${entry.name}` : entry.name;
		const full = path.join(dir, entry.name);
		if (entry.isDirectory()) files.push(...await listFiles(full, rel));
		else files.push(rel);
	}
	return files.sort();
}

function isTextTaskFile(file) {
	return /\.(json|md|mjs|js)$/i.test(file);
}

function normalizeTextFile(data) {
	const text = data.toString("utf8");
	const normalized = text.split(/\r?\n/).map((line) => line.replace(/[ \t]+$/g, "")).join("\n");
	return text.endsWith("\n") ? `${normalized.replace(/\n$/u, "")}\n` : normalized;
}

async function copyTree(from, to) {
	await mkdir(to, { recursive: true });
	for (const entry of await readdir(from, { withFileTypes: true })) {
		const source = path.join(from, entry.name);
		const target = path.join(to, entry.name);
		if (entry.isDirectory()) await copyTree(source, target);
		else {
			const data = await readFile(source);
			await writeFile(target, isTextTaskFile(entry.name) ? normalizeTextFile(data) : data);
		}
	}
}

function inputExample(inputs) {
	if (!inputs?.length) return "无参数";
	return inputs.slice(0, 3).map((input) => `${input}=${input.toLowerCase().includes("url") ? "https://example.com/video" : "<value>"}`).join(" ");
}

