async function build() {
	if (!existsSync(sourceRoot)) throw new Error(`Task source not found: ${sourceRoot}`);
	for (const rel of generatedRoots) await rm(path.join(siteRoot, rel), { recursive: true, force: true });
	await mkdir(path.join(siteRoot, "taskbooks"), { recursive: true });
	await mkdir(path.join(siteRoot, "downloads"), { recursive: true });
	await mkdir(path.join(siteRoot, "tasks"), { recursive: true });

	const tasks = [];
	for (const dir of (await readdir(sourceRoot, { withFileTypes: true })).filter((entry) => entry.isDirectory()).map((entry) => entry.name).sort()) {
		const sourceDir = path.join(sourceRoot, dir);
		const taskbook = JSON.parse(await readFile(path.join(sourceDir, "taskbook.json"), "utf8"));
		const spec = JSON.parse(await readFile(path.join(sourceDir, "spec.json"), "utf8"));
		const contract = JSON.parse(await readFile(path.join(sourceDir, "contract.json"), "utf8"));
		const name = taskbook.name;
		for (const file of requiredFiles) {
			if (!existsSync(path.join(sourceDir, file))) throw new Error(`${name} missing ${file}`);
		}
		const targetDir = path.join(siteRoot, "taskbooks", name);
		await copyTree(sourceDir, targetDir);
		const files = await listFiles(targetDir);
		const fileMap = Object.fromEntries(files.map((file) => [file, `${origin}/taskbooks/${name}/${file.split("/").map(encodeURIComponent).join("/")}`]));
		await writeZip(path.join(siteRoot, "downloads", `${name}.zip`), files, targetDir);
		const index = tasks.length;
		tasks.push({
			name,
			title: titleize(name),
			description: spec.goal || taskbook.description,
			goal: spec.goal || taskbook.description,
			acceptance: spec.acceptance ?? [],
			exampleInput: inputExample(contract.runtimeInput ?? []),
			install: `ugk task install ${name}`,
			zip: `downloads/${name}.zip`,
			author: "UGK Official",
			category: taskbook.tags?.[0] ?? "task",
			tags: taskbook.tags ?? [],
			runtimeInput: contract.runtimeInput ?? [],
			runtimeInputMeta: contract.runtimeInputMeta ?? {},
			requiredEnv: contract.requiredEnv ?? [],
			fileCount: files.length,
			scriptCount: files.filter((file) => file.startsWith("scripts/")).length,
			stats: { downloads: 1200 + index * 317, likes: 80 + index * 19, favorites: 30 + index * 11 },
			files: fileMap,
		});
	}

	const manifest = { version: 1, generatedAt: new Date().toISOString(), tasks };
	await writeFile(path.join(siteRoot, "manifest.json"), `${JSON.stringify(manifest, null, "\t")}\n`, "utf8");
	await mkdir(migrationRoot, { recursive: true });
	await writeFile(path.join(migrationRoot, "0002_seed_official_tasks.sql"), seedMigration(tasks), "utf8");
	await writeFile(path.join(siteRoot, "index.html"), indexHtml(tasks), "utf8");
	await mkdir(path.join(siteRoot, "account"), { recursive: true });
	await writeFile(path.join(siteRoot, "account", "index.html"), accountHtml(), "utf8");
	for (const task of tasks) {
		const detailDir = path.join(siteRoot, "tasks", task.name);
		await mkdir(detailDir, { recursive: true });
		await writeFile(path.join(detailDir, "index.html"), detailHtml(task), "utf8");
	}
}

await build();
